const x={},n='<h1 id="&#x6587;&#x7AE0;&#x7CBE;&#x8BFB;&#x4E4B;&#x8BBE;&#x8BA1;&#x539F;&#x5219;/&#x6A21;&#x5F0F;"><a href="#&#x6587;&#x7AE0;&#x7CBE;&#x8BFB;&#x4E4B;&#x8BBE;&#x8BA1;&#x539F;&#x5219;/&#x6A21;&#x5F0F;"></a>&#x6587;&#x7AE0;&#x7CBE;&#x8BFB;&#x4E4B;&#x8BBE;&#x8BA1;&#x539F;&#x5219;/&#x6A21;&#x5F0F;</h1>\n<h2 id="&#x8BBE;&#x8BA1;&#x539F;&#x5219;&#xFF1A;SOLID&#x539F;&#x5219;"><a href="#&#x8BBE;&#x8BA1;&#x539F;&#x5219;&#xFF1A;SOLID&#x539F;&#x5219;"></a>&#x8BBE;&#x8BA1;&#x539F;&#x5219;&#xFF1A;SOLID&#x539F;&#x5219;</h2>\n<ul>\n<li>Single Responsibility Principle &#x5355;&#x4E00;&#x539F;&#x5219;&#xFF1B;\n<ul>\n<li>&#x4E00;&#x79CD;Class&#x53EA;&#x8D1F;&#x8D23;&#x4E00;&#x7C7B;&#x4E8B;&#x60C5;</li>\n</ul>\n</li>\n<li>Open/Closed Principle &#x5F00;&#x95ED;&#x539F;&#x5219;&#xFF1B;\n<ul>\n<li>&#x5141;&#x8BB8;&#x5728;&#x4E0D;&#x6539;&#x53D8;&#x5DF2;&#x6709;&#x4EE3;&#x7801;&#x524D;&#x63D0;&#x4E0B;&#x6DFB;&#x52A0;&#x65B0;&#x529F;&#x80FD;</li>\n</ul>\n</li>\n<li>Liskov Substitution Principle &#x91CC;&#x6C0F;&#x66FF;&#x6362;&#x539F;&#x5219;&#xFF1B;\n<ul>\n<li>&#x4E0D;&#x8981;&#x4ECE;&#x53EF;&#x5B9E;&#x4F8B;&#x5316;&#x7684;&#x7236;&#x7C7B;&#x4E2D;&#x7EE7;&#x627F;&#xFF08;&#x65B9;&#x6CD5;&#xFF09;&#xFF0C;&#x800C;&#x662F;&#x8981;&#x4F7F;&#x7528;&#x57FA;&#x4E8E;&#x62BD;&#x8C61;&#x7C7B;&#x548C;&#x63A5;&#x53E3;&#x7684;&#x7EE7;&#x627F;&#x3002;</li>\n</ul>\n</li>\n<li>Interface Segregation Principle &#x63A5;&#x53E3;&#x9694;&#x79BB;&#x539F;&#x5219;&#xFF1B;\n<ul>\n<li>Clients should not be forced to depend upon interfaces that they do not use. &#x5BF9;&#x4E8E;&#x975E;&#x5FC5;&#x987B;&#x7684;&#x53C2;&#x6570;&#x505A;&#x53EF;&#x9009;&#x914D;&#x7F6E;&#xFF0C;&#x7CBE;&#x7B80;&#x63A5;&#x53E3;&#xFF0C;&#x7B80;&#x5316;&#x4F7F;&#x7528;</li>\n</ul>\n</li>\n<li>Dependency Inversion Principle &#x4F9D;&#x8D56;&#x53CD;&#x8F6C;&#x539F;&#x5219;\n<ul>\n<li>High-level modules should not depend on low-level modules.</li>\n<li>Both should depend on abstractions.Abstractions should not depend upon details. Details should depend on abstractions.</li>\n<li>&#x964D;&#x4F4E;&#x8026;&#x5408;&#xFF0C;&#x65B9;&#x4FBF;&#x91CD;&#x6784;&#x8DDF;&#x6269;&#x5C55;</li>\n</ul>\n</li>\n</ul>\n<h2 id="&#x8BBE;&#x8BA1;&#x6A21;&#x5F0F;"><a href="#&#x8BBE;&#x8BA1;&#x6A21;&#x5F0F;"></a>&#x8BBE;&#x8BA1;&#x6A21;&#x5F0F;</h2>\n<h3 id="Creational Patterns"><a href="#Creational Patterns"></a>Creational Patterns</h3>\n<ul>\n<li>Fatory Method</li>\n<li>SingleTon</li>\n</ul>\n<h3 id="Behavioral Patterns"><a href="#Behavioral Patterns"></a>Behavioral Patterns</h3>\n<ul>\n<li>Strategy</li>\n<li>Observer</li>\n<li>Iterator</li>\n</ul>\n<h3 id="Structural Patterns"><a href="#Structural Patterns"></a>Structural Patterns</h3>\n<ul>\n<li>Adapter</li>\n<li>Decorator</li>\n<li>Proxy</li>\n</ul>\n<h2 id="&#x8BBE;&#x8BA1;&#x539F;&#x5219; vs &#x8BBE;&#x8BA1;&#x6A21;&#x5F0F;"><a href="#&#x8BBE;&#x8BA1;&#x539F;&#x5219; vs &#x8BBE;&#x8BA1;&#x6A21;&#x5F0F;"></a>&#x8BBE;&#x8BA1;&#x539F;&#x5219; vs &#x8BBE;&#x8BA1;&#x6A21;&#x5F0F;</h2>\n<ul>\n<li>&#x7B80;&#x6D01;&#x7406;&#x89E3;&#xFF1A;&#x8BBE;&#x8BA1;&#x6A21;&#x5F0F;&#xFF08;&#x8BED;&#x8A00;&#x76F8;&#x5173;&#xFF09;&#x662F;&#x5BF9;&#x8BBE;&#x8BA1;&#x539F;&#x5219;&#xFF08;&#x8BED;&#x8A00;&#x72EC;&#x7ACB;&#xFF09;&#x7684;&#x5B9E;&#x73B0;</li>\n<li>&#x957F;&#x6587;&#x7406;&#x89E3;\n<ul>\n<li>Design principles provide high level guidelines to design better software applications. They do not provide implementation guidelines and are not bound to any programming language.</li>\n<li>Design Pattern provides low-level solutions related to implementation, of commonly occurring object-oriented problems. In other words, design pattern suggests a specific implementation for the specific object-oriented programming problem.</li>\n</ul>\n</li>\n</ul>\n<h2 id="Reference"><a href="#Reference"></a>Reference</h2>\n<ul>\n<li>https://github.com/ryanmcdermott/clean-code-javascript#solid</li>\n<li>https://www.tutorialsteacher.com/articles/difference-between-design-principle-and-design-pattern</li>\n<li>https://github.com/sohamkamani/javascript-design-patterns-for-humans#behavioral-design-patterns</li>\n<li>https://github.com/lpxxn/rust-design-pattern</li>\n</ul>\n<h1 id="&#x5173;&#x4E8E;&#x7EE7;&#x627F;"><a href="#&#x5173;&#x4E8E;&#x7EE7;&#x627F;"></a>&#x5173;&#x4E8E;&#x7EE7;&#x627F;</h1>\n<p>&#x8C08;&#x5230;&#x7EE7;&#x627F;&#x5C31;&#x4F1A;&#x8BF4;&#x5230;&#x201C;&#x7C7B;&#x201D;&#xFF0C;&#x201C;&#x7C7B;&#x201D;&#x5C01;&#x88C5;&#x7684;&#x662F;&#x6570;&#x636E;&#xFF0C;&#x662F;&#x5BF9;&#x540C;&#x4E00;&#x7C7B;&#x6570;&#x636E;&#x5B9E;&#x4F53;&#x4EE5;&#x53CA;&#x5176;&#x5904;&#x7406;&#x65B9;&#x6CD5;&#x7684;&#x62BD;&#x8C61;&#x3002;</p>\n<ul>\n<li>\n<p>&#x76EE;&#x7684;&#xFF1A;</p>\n<ol>\n<li>&#x4EE3;&#x7801;&#x590D;&#x7528;</li>\n<li>&#x591A;&#x6001;&#xFF08;&#x540C;&#x4E00;&#x64CD;&#x4F5C;&#x4F5C;&#x7528;&#x4E8E;&#x4E0D;&#x540C;&#x7684;&#x5BF9;&#x8C61;&#xFF0C;&#x53EF;&#x4EE5;&#x6709;&#x4E0D;&#x540C;&#x7684;&#x89E3;&#x91CA;&#xFF0C;&#x4EA7;&#x751F;&#x4E0D;&#x540C;&#x7684;&#x6267;&#x884C;&#x7ED3;&#x679C;&#x3002;&#x5B9E;&#x73B0;&#x65B9;&#x5F0F;&#xFF1A;&#x8986;&#x76D6;&#xFF0C;&#x91CD;&#x8F7D;&#xFF1B;&#x67D0;&#x79CD;&#x7A0B;&#x5EA6;&#x4E5F;&#x7B97;&#x4EE3;&#x7801;&#x590D;&#x7528;&#xFF1F;&#xFF09;\n<ul>\n<li>&#x8986;&#x76D6;&#xFF1A;&#x6307;&#x5B50;&#x7C7B;&#x91CD;&#x65B0;&#x5B9A;&#x4E49;&#x7236;&#x7C7B;&#x65B9;&#x6CD5;&#xFF0C;&#x4F8B;&#x5982;js&#x7684;prototype</li>\n<li>&#x91CD;&#x8F7D;&#xFF1A;&#x591A;&#x4E2A;&#x540C;&#x540D;&#x4F46;&#x53C2;&#x6570;&#x4E0D;&#x540C;&#x7684;&#x65B9;&#x6CD5;&#xFF0C;&#x4F8B;&#x5982; Rust &#x51FD;&#x6570;&#x6A21;&#x677F;</li>\n</ul>\n</li>\n</ol>\n</li>\n<li>\n<p>&#x7EE7;&#x627F;&#x65B9;&#x5F0F;&#xFF1A;</p>\n<ol>\n<li>&#x6B63;&#x7EDF;&#xFF1A;C++,java</li>\n<li>&#x6A21;&#x62DF;&#xFF1A;js&#x539F;&#x578B;&#x94FE;</li>\n<li>&#x65E0;&#xFF1A;Rust trait &#x7EC4;&#x5408;&#x5B9E;&#x73B0;&#x591A;&#x6001;\n&#x601D;&#x8003;&#xFF1A;Rust &#x7684;&#x7F16;&#x7A0B;&#x5EFA;&#x6A21;&#x6A21;&#x5F0F;&#x66F4;&#x50CF;&#x662F;&#x7EC4;&#x5408;&#xFF08;Composition&#xFF09; &#x800C;&#x4E0D;&#x662F;&#x7EE7;&#x627F;&#xFF08;Inheritance&#xFF09;&#xFF1F;&#x6709;&#x70B9;&#x7C7B;&#x4F3C; Vue3 &#x9009;&#x62E9; Composition-API &#x4EE3;&#x66FF; Class-Option&#xFF1F;</li>\n</ol>\n</li>\n</ul>\n<p>&#x591A;&#x6001;&#x56FE;&#x89E3;&#xFF1A;<img src="https://pic1.zhimg.com/80/v2-6f26625afb5174fa5228e817cd68a7db_1440w.jpg?source=1940ef5c" alt="&#x591A;&#x6001;"></p>\n<p><a href="https://www.zhihu.com/question/66038192/answer/1898435232">&#x56FE;&#x6765;&#x6E90;</a></p>\n<h3 id="Reference"><a href="#Reference"></a>Reference</h3>\n<ul>\n<li><a href="https://fengliang.io/RustWHY/design_choices/why_not_inheritance.html">&#x4E3A;&#x4EC0;&#x4E48;Rust&#x6CA1;&#x6709;&#x7EE7;&#x627F;&#xFF1F;</a></li>\n<li>https://www.runoob.com/rust/rust-object.html</li>\n</ul>\n<h1 id="&#x5173;&#x4E8E;&#x9762;&#x5411;&#x5BF9;&#x8C61;"><a href="#&#x5173;&#x4E8E;&#x9762;&#x5411;&#x5BF9;&#x8C61;"></a>&#x5173;&#x4E8E;&#x9762;&#x5411;&#x5BF9;&#x8C61;</h1>\n<ul>\n<li>&#x89E3;&#x91CA;&#xFF1A;&#x9762;&#x5411;&#x5BF9;&#x8C61;&#x7684;&#x7F16;&#x7A0B;&#x8BED;&#x8A00;&#x901A;&#x5E38;&#x5B9E;&#x73B0;&#x4E86;&#x6570;&#x636E;&#x7684;&#x5C01;&#x88C5;&#x4E0E;&#x7EE7;&#x627F;&#x5E76;&#x80FD;&#x57FA;&#x4E8E;&#x6570;&#x636E;&#x8C03;&#x7528;&#x65B9;&#x6CD5;&#x3002;</li>\n<li>&#x6709;&#xFF1A;js&#x4E00;&#x5207;&#x90FD;&#x662F;&#x5BF9;&#x8C61;</li>\n<li>&#x65E0;&#xFF1A;Rust &#x4E0D;&#x662F;&#x9762;&#x5411;&#x5BF9;&#x8C61;&#x7684;&#x7F16;&#x7A0B;&#x8BED;&#x8A00;&#xFF0C;&#x4F46;&#x8FD9;&#x4E9B;&#x529F;&#x80FD;&#x90FD;&#x5F97;&#x4EE5;&#x5B9E;&#x73B0;&#x3002;</li>\n</ul>\n<h1 id="React&#x72B6;&#x6001;&#x7BA1;&#x7406;"><a href="#React&#x72B6;&#x6001;&#x7BA1;&#x7406;"></a>React&#x72B6;&#x6001;&#x7BA1;&#x7406;</h1>\n<ul>\n<li>Redux\n<ul>\n<li>&#x901A;&#x8FC7;props&#x6CE8;&#x5165; dispatch/state&#xFF0C;&#x89C4;&#x907F;&#x4E86; useContext &#x65B9;&#x6848;&#x53EF;&#x80FD;&#x5BFC;&#x81F4;&#x7684;&#x91CD;&#x590D;&#x6E32;&#x67D3;</li>\n</ul>\n</li>\n<li>Mobx &#xFF08;&#x6709;&#x70B9;&#x7C7B;&#x4F3C;createContext + useContext + reactivity&#xFF09;\n<ul>\n<li>&#x7279;&#x5F81;&#xFF1A;Mobx + React &#x7C7B;&#x4F3C;&#x7B49;&#x4E8E; Vue</li>\n</ul>\n</li>\n<li>createContext + useContext + useReducer\n<ul>\n<li>&#x5751;&#xFF1A;createContext &#x8FD4;&#x56DE;&#x7684; Provider &#x4E2D; value&#x53D8;&#x5316;&#x4F1A;&#x89E6;&#x53D1;&#x6240;&#x6709;&#x5B50;&#x7EC4;&#x4EF6;&#x91CD;&#x590D;&#x6E32;&#x67D3;\n<ul>\n<li>&#x5173;&#x8054;&#x601D;&#x8003;&#xFF1A;&#x8FD9;&#x79CD;&#x65B9;&#x6848;&#x9002;&#x7528;&#x4E8E;&#x5C0F;&#x578B;&#x7684;&#x72B6;&#x6001;&#x7BA1;&#x7406;&#xFF1F;</li>\n</ul>\n</li>\n<li>Todo&#xFF1A;&#x4E86;&#x89E3;&#x91CD;&#x590D;&#x6E32;&#x67D3;&#x7684;&#x8FD0;&#x8F6C;&#x673A;&#x5236;</li>\n<li>&#x4F18;&#x5316;&#xFF1A;&#x5BF9;&#x6E32;&#x67D3;&#x505A; useMemo</li>\n</ul>\n</li>\n</ul>\n<h1 id="&#x6587;&#x7AE0;&#x7CBE;&#x8BFB;&#x4E4B;&#x524D;&#x7AEF;&#x6846;&#x67B6;&#x8BBE;&#x8BA1;"><a href="#&#x6587;&#x7AE0;&#x7CBE;&#x8BFB;&#x4E4B;&#x524D;&#x7AEF;&#x6846;&#x67B6;&#x8BBE;&#x8BA1;"></a>&#x6587;&#x7AE0;&#x7CBE;&#x8BFB;&#x4E4B;&#x524D;&#x7AEF;&#x6846;&#x67B6;&#x8BBE;&#x8BA1;</h1>\n<h2 id="&#x7EC4;&#x4EF6;&#x7C7B;&#x578B;"><a href="#&#x7EC4;&#x4EF6;&#x7C7B;&#x578B;"></a>&#x7EC4;&#x4EF6;&#x7C7B;&#x578B;</h2>\n<ul>\n<li>&#x7EAF;&#x5C55;&#x793A;&#x578B;&#x7684;&#x7EC4;&#x4EF6;&#xFF0C;&#x6570;&#x636E;&#x8FDB;&#xFF0C;DOM&#x51FA;&#xFF0C;&#x76F4;&#x89C2;&#x660E;&#x4E86;</li>\n<li>&#x63A5;&#x5165;&#x578B;&#x7EC4;&#x4EF6;&#xFF0C;&#x5728;React&#x573A;&#x666F;&#x4E0B;&#x7684;container component&#xFF0C;&#x8FD9;&#x79CD;&#x7EC4;&#x4EF6;&#x4F1A;&#x8DDF;&#x6570;&#x636E;&#x5C42;&#x7684;service&#x6253;&#x4EA4;&#x9053;&#xFF0C;&#x4F1A;&#x5305;&#x542B;&#x4E00;&#x4E9B;&#x8DDF;&#x670D;&#x52A1;&#x5668;&#x6216;&#x8005;&#x8BF4;&#x6570;&#x636E;&#x6E90;&#x6253;&#x4EA4;&#x9053;&#x7684;&#x903B;&#x8F91;&#xFF0C;container&#x4F1A;&#x628A;&#x6570;&#x636E;&#x5411;&#x4E0B;*&#x4F20;&#x9012;&#x7ED9;&#x5C55;&#x793A;&#x578B;&#x7EC4;&#x4EF6;</li>\n<li>&#x4EA4;&#x4E92;&#x578B;&#x7EC4;&#x4EF6;&#xFF0C;&#x5178;&#x578B;&#x7684;&#x4F8B;&#x5B50;&#x662F;&#x5BF9;&#x4E8E;&#x8868;&#x5355;&#x7EC4;&#x4EF6;&#x7684;&#x5C01;&#x88C5;&#x548C;&#x52A0;&#x5F3A;&#xFF0C;&#x5927;&#x90E8;&#x5206;&#x7684;&#x7EC4;&#x4EF6;&#x5E93;&#x90FD;&#x662F;&#x4EE5;&#x4EA4;&#x4E92;&#x578B;&#x7EC4;&#x4EF6;&#x4E3A;&#x4E3B;&#xFF0C;&#x6BD4;&#x5982;&#x8BF4;Element UI&#xFF0C;&#x7279;&#x70B9;&#x662F;&#x6709;&#x6BD4;&#x8F83;&#x590D;&#x6742;&#x7684;&#x4EA4;&#x4E92;&#x903B;&#x8F91;&#xFF0C;&#x4F46;&#x662F;&#x662F;&#x6BD4;&#x8F83;&#x901A;&#x7528;&#x7684;&#x903B;&#x8F91;&#xFF0C;&#x5F3A;&#x8C03;&#x7EC4;&#x4EF6;&#x7684;&#x590D;&#x7528;</li>\n<li>&#x529F;&#x80FD;&#x578B;&#x7EC4;&#x4EF6;&#xFF0C;&#x4EE5;Vue&#x7684;&#x5E94;&#x7528;&#x573A;&#x666F;&#x4E3E;&#x4F8B;&#xFF0C;&#x8DEF;&#x7531;&#x7684;router-view&#x7EC4;&#x4EF6;&#x3001;transition&#x7EC4;&#x4EF6;&#xFF0C;&#x672C;&#x8EAB;&#x5E76;&#x4E0D;&#x6E32;&#x67D3;&#x4EFB;&#x4F55;&#x5185;&#x5BB9;&#xFF0C;&#x662F;&#x4E00;&#x4E2A;&#x903B;&#x8F91;&#x578B;&#x7684;&#x4E1C;&#x897F;&#xFF0C;&#x4F5C;&#x4E3A;&#x4E00;&#x79CD;&#x6269;&#x5C55;&#x6216;&#x8005;&#x662F;&#x62BD;&#x8C61;&#x673A;&#x5236;&#x5B58;&#x5728;</li>\n</ul>\n<h2 id="&#x72B6;&#x6001;&#x7BA1;&#x7406;"><a href="#&#x72B6;&#x6001;&#x7BA1;&#x7406;"></a>&#x72B6;&#x6001;&#x7BA1;&#x7406;</h2>\n<p>&#x5982;&#x4F55;&#x7BA1;&#x7406;&#x5C06;&#x4E8B;&#x4EF6;&#x6E90;&#x6620;&#x5C04;&#x5230;&#x72B6;&#x6001;&#x53D8;&#x5316;&#x7684;&#x8FC7;&#x7A0B;&#xFF0C;&#x5982;&#x4F55;&#x5C06;&#x8FD9;&#x4E2A;&#x6620;&#x5C04;&#x7684;&#x8FC7;&#x7A0B;&#x4ECE;&#x89C6;&#x56FE;&#x7EC4;&#x4EF6;&#x4E2D;&#x5265;&#x79BB;&#x51FA;&#x6765;&#xFF0C;&#x5982;&#x4F55;&#x7EC4;&#x7EC7;&#x8FD9;&#x4E00;&#x90E8;&#x5206;&#x4EE3;&#x7801;&#x6765;&#x63D0;&#x9AD8;&#x53EF;&#x7EF4;&#x62A4;&#x6027;&#xFF0C;&#x662F;&#x72B6;&#x6001;&#x7BA1;&#x7406;&#x8981;&#x89E3;&#x51B3;&#x7684;&#x672C;&#x8D28;&#x95EE;&#x9898;</p>\n<h2 id="CSS&#x65B9;&#x6848;"><a href="#CSS&#x65B9;&#x6848;"></a>CSS&#x65B9;&#x6848;</h2>\n<ul>\n<li>css modules</li>\n<li>css-in-js</li>\n</ul>\n<h2 id="&#x6784;&#x5EFA;&#x5DE5;&#x5177;"><a href="#&#x6784;&#x5EFA;&#x5DE5;&#x5177;"></a>&#x6784;&#x5EFA;&#x5DE5;&#x5177;</h2>\n<p>&#x89E3;&#x51B3;&#x7684;&#x95EE;&#x9898;</p>\n<ul>\n<li>&#x4EFB;&#x52A1;&#x7684;&#x81EA;&#x52A8;&#x5316;</li>\n<li>&#x5F00;&#x53D1;&#x4F53;&#x9A8C;&#x548C;&#x6548;&#x7387;&#xFF08;&#x65B0;&#x7684;&#x8BED;&#x8A00;&#x529F;&#x80FD;&#xFF0C;&#x8BED;&#x6CD5;&#x7CD6;&#xFF0C;hot reload &#x7B49;&#x7B49;&#xFF09;</li>\n<li>&#x90E8;&#x7F72;&#x76F8;&#x5173;&#x7684;&#x9700;&#x6C42;</li>\n<li>&#x7F16;&#x8BD1;&#x65F6;&#x4F18;&#x5316;</li>\n</ul>\n<h2 id="Reference"><a href="#Reference"></a>Reference</h2>\n<ul>\n<li><a href="https://juejin.cn/post/6844903510455107598">Evanyou &#x804A;&#x804A;&#x524D;&#x7AEF;&#x6846;&#x67B6;</a></li>\n</ul>\n<h1 id="CSS Animation,Transition &#x539F;&#x7406;"><a href="#CSS Animation,Transition &#x539F;&#x7406;"></a>CSS Animation,Transition &#x539F;&#x7406;</h1>\n<ul>\n<li>\n<p>GPU&#x6BD4;&#x8F83;&#x64C5;&#x957F;&#x4E8E;&#xFF1A;</p>\n<ul>\n<li>\n<p>&#x7ED8;&#x5236;&#x4F4D;&#x56FE;&#x5230;&#x5C4F;&#x5E55;</p>\n</li>\n<li>\n<p>&#x91CD;&#x590D;&#x7684;&#x7ED8;&#x5236;&#x540C;&#x4E00;&#x4E2A;&#x4F4D;&#x56FE;</p>\n</li>\n<li>\n<p>&#x5728;&#x4E0D;&#x540C;&#x7684;&#x4F4D;&#x7F6E;&#xFF0C;&#x4EE5;&#x4E0D;&#x540C;&#x7684;&#x65CB;&#x8F6C;&#x89D2;&#x5EA6;&#xFF0C;&#x6216;&#x8005;&#x4E0D;&#x540C;&#x7684;&#x7F29;&#x653E;&#x5927;&#x5C0F;&#x6765;&#x7ED8;&#x5236;&#x540C;&#x4E00;&#x4E2A;&#x4F4D;&#x56FE;&#x3002;</p>\n</li>\n</ul>\n</li>\n<li>\n<p>GPU&#x76F8;&#x5BF9;&#x6162;&#x7684;&#x5730;&#x65B9;&#xFF1A;</p>\n<ul>\n<li>&#x5C06;&#x4F4D;&#x56FE;&#x52A0;&#x8F7D;&#x5230;&#x663E;&#x5B58;&#x91CC;&#x3002;</li>\n</ul>\n</li>\n</ul>\n<p>&#x4F8B;&#x5B50;&#xFF1A;</p>\n<pre><code class="language-css"><span class="hljs-comment">/*hover&#x7684;&#x65F6;&#x5019;height&#x53D8;&#x5316; 100 -&gt; 200&#x7684;&#x8FC7;&#x7A0B;&#x4E2D;&#x91CD;&#x590D;&#x8BA1;&#x7B97;&#x5143;&#x7D20;&#x5F53;&#x524D;&#x4F4D;&#x56FE;&#x7136;&#x540E;&#x56DE;&#x4F20;&#x7ED9;GPU&#x7ED8;&#x5236;*/</span>\n<span class="hljs-selector-tag">div</span> {   \n    <span class="hljs-attribute">height</span>: <span class="hljs-number">100px</span>;   \n    <span class="hljs-attribute">transition</span>: height <span class="hljs-number">1s</span> linear;   \n}   \n\n<span class="hljs-selector-tag">div</span><span class="hljs-selector-pseudo">:hover</span> {   \n    <span class="hljs-attribute">height</span>: <span class="hljs-number">200px</span>;   \n} \n\n<span class="hljs-comment">/*\nCSS&#x7684;transform&#x5C5E;&#x6027;&#x4E0D;&#x4F1A;&#x6539;&#x53D8;&#x5143;&#x7D20;&#x7684;&#x5E03;&#x5C40;&#xFF0C;&#x4E5F;&#x4E0D;&#x4F1A;&#x5F71;&#x54CD;&#x5230;&#x5176;&#x5468;&#x56F4;&#x7684;&#x5143;&#x7D20;&#x3002;&#x5B83;&#x628A;&#x5143;&#x7D20;&#x5F53;&#x505A;&#x4E00;&#x4E2A;&#x6574;&#x4F53;&#x770B;&#x5F85;&#x2014;&#x2014;&#x7F29;&#x653E;&#x6574;&#x4E2A;&#x5143;&#x7D20;&#x3001;&#x65CB;&#x8F6C;&#x6574;&#x4E2A;&#x5143;&#x7D20;&#x6216;&#x8005;&#x79FB;&#x52A8;&#x6574;&#x4E2A;&#x5143;&#x7D20;&#x3002;\n&#x6240;&#x4EE5;&#x4F4D;&#x56FE;&#x53EA;&#x4F1A;&#x5728;cpu&#x8DDF;GPU &#x4E4B;&#x95F4;&#x4F20;&#x9012;&#x4E00;&#x6B21;&#xFF0C;scale&#x7684;&#x91CD;&#x65B0;&#x7ED8;&#x5236;&#x53EA;&#x53D1;&#x751F;&#x5728;GPU&#xFF0C;&#x800C;&#x4E0D;&#x4F1A;&#x963B;&#x585E;&#x4E3B;&#x7EBF;&#x7A0B;&#xFF0C;&#x4E5F;&#x5C31;&#x662F;&#x66F4;&#x52A0;&#x6D41;&#x7545;&#xFF1F;\n*/</span>\n<span class="hljs-selector-tag">div</span> {   \n    <span class="hljs-attribute">transform</span>: <span class="hljs-built_in">scale</span>(<span class="hljs-number">0.5</span>);   \n    <span class="hljs-attribute">transition</span>: transform <span class="hljs-number">1s</span> linear;   \n}   \n     \n<span class="hljs-selector-tag">div</span><span class="hljs-selector-pseudo">:hover</span> {   \n    <span class="hljs-attribute">transform</span>: <span class="hljs-built_in">scale</span>(<span class="hljs-number">1.0</span>);   \n}  \n</code></pre>\n<h2 id="&#x603B;&#x7ED3;"><a href="#&#x603B;&#x7ED3;"></a>&#x603B;&#x7ED3;</h2>\n<p>&#x9009;&#x62E9;&#x72EC;&#x7ACB;&#x6027;&#x6BD4;&#x8F83;&#x5F3A;&#x7684;CSS&#x5C5E;&#x6027;&#x6709;&#x52A9;&#x4E8E;&#x6539;&#x5584;&#x52A8;&#x753B;&#x6548;&#x679C;&#xFF1A;transform&#xFF0C;opacity&#xFF0C;filter &#xFF08;&#x4F9D;&#x8D56;&#x4E8E;&#x8FC7;&#x6EE4;&#x5668;&#x7684;&#x590D;&#x6742;&#x5EA6;&#x548C;&#x6D4F;&#x89C8;&#x5668;&#xFF09;</p>\n<p>&#x62D3;&#x5C55;&#xFF1A;&#x6E32;&#x67D3;&#x7EBF;&#x7A0B;&#x5206;&#x4E3A; &#x4E3B;&#x7EBF;&#x7A0B; (main thread) &#x548C; &#x5408;&#x6210;&#x7EBF;&#x7A0B; (compositor thread)</p>\n<h2 id="Reference"><a href="#Reference"></a>Reference</h2>\n<ul>\n<li>https://www.jb51.net/css/348357.html</li>\n</ul>\n<h1 id="Vue&#x8FD0;&#x884C;&#x65F6;&#x9519;&#x8BEF;&#x5904;&#x7406;"><a href="#Vue&#x8FD0;&#x884C;&#x65F6;&#x9519;&#x8BEF;&#x5904;&#x7406;"></a>Vue&#x8FD0;&#x884C;&#x65F6;&#x9519;&#x8BEF;&#x5904;&#x7406;</h1>\n<p>Vue&#x6E90;&#x7801;&#x91CC;&#x9762;lifeCycle/watch/directive/transition&#x7B49;&#x7684;callback/hook&#x7B49;&#x4E00;&#x822C;&#x4F1A;&#x88AB;&#x5C01;&#x88C5;&#x6267;&#x884C;</p>\n<pre><code class="language-js"> <span class="hljs-keyword">const</span> res = callWithAsyncErrorHandling(hook, target, type, args)\n</code></pre>\n<ul>\n<li>&#x5C01;&#x88C5;&#x6267;&#x884C;&#x8981;&#x7D20;&#xFF1A;\n<ul>\n<li>fn: Function,</li>\n<li>instance: ComponentInternalInstance | null,</li>\n<li>type: ErrorTypes,</li>\n</ul>\n</li>\n<li>&#x9519;&#x8BEF;&#x5206;&#x7C7B;&#xFF1A;LifecycleHooks | ErrorCodes&#xFF08;&#x5176;&#x4ED6;&#x51FD;&#x6570;&#x6267;&#x884C;&#x70B9;&#xFF1A;callback + hook&#x7B49;&#xFF09;</li>\n<li>&#x540C;&#x6B65;&#x9519;&#x8BEF;&#x5904;&#x7406;&#xFF1A;&#x5C1D;&#x8BD5;&#x51FD;&#x6570;&#x8FD0;&#x884C;&#x5904;&#x7406;&#x540C;&#x6B65;&#x9519;&#x8BEF;&#xFF0C;&#x5E76;&#x641C;&#x96C6;&#x8FD4;&#x56DE;&#x503C;</li>\n<li>&#x5F02;&#x6B65;&#x9519;&#x8BEF;&#x5904;&#x7406;&#xFF1A;&#x6839;&#x636E;&#x8FD4;&#x56DE;&#x503C;&#x662F;&#x5426;Promise&#x6765;&#x5904;&#x7406;&#x5F02;&#x6B65;&#x9519;&#x8BEF;</li>\n</ul>\n<h2 id="Reference"><a href="#Reference"></a>Reference</h2>\n<ul>\n<li><a href="https://github.com/vuejs/core/blob/main/packages/runtime-core/src/errorHandling.ts">@vue/runtime-core/errorHandling</a></li>\n</ul>\n<h1 id="&#x63D2;&#x4EF6;&#x5BF9;&#x6BD4;&#xFF08;Vue vs React&#xFF09;"><a href="#&#x63D2;&#x4EF6;&#x5BF9;&#x6BD4;&#xFF08;Vue vs React&#xFF09;"></a>&#x63D2;&#x4EF6;&#x5BF9;&#x6BD4;&#xFF08;Vue vs React&#xFF09;</h1>\n<h2 id="&#x63D2;&#x4EF6;"><a href="#&#x63D2;&#x4EF6;"></a>&#x63D2;&#x4EF6;</h2>\n<ol>\n<li>Vue&#x63D2;&#x4EF6;</li>\n</ol>\n<pre><code class="language-js"><span class="hljs-comment">// calls `MyPlugin.install(Vue)`</span>\nVue.use(MyPlugin)\n\n<span class="hljs-keyword">new</span> Vue({\n  <span class="hljs-comment">//... options</span>\n})\n<span class="hljs-comment">/**\n * \n * &#x9002;&#x914D; Vue3&#x7684; Composition-API&#x573A;&#x666F;\n * 1. &#x5728;MyPlugin&#x521D;&#x59CB;&#x5316;&#x9636;&#x6BB5; app.provide(injectKey)&#x6CE8;&#x5165;&#x5B9E;&#x4F8B;\n * 2. &#x5728;MyPlugin use&#x9636;&#x6BB5; app.inject(injectKey)&#x83B7;&#x53D6;&#x5B9E;&#x4F8B;\n * \n * Class &#x573A;&#x666F;\n * 1. &#x521D;&#x59CB;&#x5316;&#x9636;&#x6BB5; &#x628A; MyPlugin &#x9010;&#x6B65; mixin &#x5230;&#x5B50;&#x7EC4;&#x4EF6;\n * 2. &#x8C03;&#x7528;&#x9636;&#x6BB5;&#x76F4;&#x63A5;&#x5728;&#x7EC4;&#x4EF6;&#x5B9E;&#x4F8B;&#x4E0A;&#x83B7;&#x53D6;\n</span></code></pre>\n<ol start="2">\n<li>React&#x63D2;&#x4EF6;</li>\n</ol>\n<pre><code class="language-js"><span class="hljs-comment">// &#x4F8B;&#x5B50;</span>\n &lt;Provider store={store}&gt;\n &lt;/Provider&gt;\n</code></pre>\n<p>// &#x4F7F;&#x7528;&#x5730;&#x65B9;&#xFF1A;&#x4E00;&#x822C;&#x9700;&#x8981;&#x5BF9;&#x7EC4;&#x4EF6;&#x505A;&#x4E8C;&#x6B21;&#x5C01;&#x88C5;&#x8FDB;&#x884C;connect&#xFF0C;&#x7136;&#x540E;&#x53EF;&#x4EE5;useDispatch&#xFF0C;<strong>&#x7C7B;&#x4F3C;Vue inject&#xFF1F;</strong></p>\n<h3 id="&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;&#xFF08;Vuex vs Redux&#xFF09;"><a href="#&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;&#xFF08;Vuex vs Redux&#xFF09;"></a>&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;&#xFF08;Vuex vs Redux&#xFF09;</h3>\n<ol>\n<li>Vuex&#x63D2;&#x4EF6;</li>\n</ol>\n<pre><code class="language-js"><span class="hljs-comment">// &#x63D2;&#x4EF6;&#x6A21;&#x677F;</span>\n<span class="hljs-keyword">const</span> myPlugin = <span class="hljs-function">(<span class="hljs-params">store</span>) =&gt;</span> {\n  <span class="hljs-comment">// called when the store is initialized</span>\n  store.subscribe(<span class="hljs-function">(<span class="hljs-params">mutation, state</span>) =&gt;</span> {\n    <span class="hljs-comment">// called after every mutation.</span>\n    <span class="hljs-comment">// The mutation comes in the format of `{ type, payload }`.</span>\n  })\n}\n</code></pre>\n<pre><code class="language-js"><span class="hljs-comment">// &#x63D2;&#x4EF6;&#x4F7F;&#x7528;</span>\n<span class="hljs-keyword">const</span> store = createStore({\n  <span class="hljs-comment">// ...</span>\n  <span class="hljs-attr">plugins</span>: [myPlugin]\n})\n</code></pre>\n<p>// &#x63D2;&#x4EF6;&#x6848;&#x4F8B;\n<a href="https://github.com/robinvdvleuten/vuex-persistedstate">vuex-persistedstate</a>&#x901A;&#x8FC7;&#x5BF9;mutation&#x7684;&#x62E6;&#x622A;&#xFF0C;&#x5BF9;&#x6A21;&#x5757;paths&#x8FDB;&#x884C;&#x7CBE;&#x51C6;&#x6301;&#x4E45;&#x5316;</p>\n<ol start="2">\n<li>Redux &#x4E2D;&#x95F4;&#x4EF6;</li>\n</ol>\n<pre><code class="language-js"><span class="hljs-comment">// &#x63D2;&#x4EF6;&#x4F8B;&#x5B50;</span>\n<span class="hljs-keyword">const</span> logger = <span class="hljs-function"><span class="hljs-params">store</span> =&gt;</span> <span class="hljs-function"><span class="hljs-params">next</span> =&gt;</span> <span class="hljs-function"><span class="hljs-params">action</span> =&gt;</span> {\n  <span class="hljs-built_in">console</span>.log(<span class="hljs-string">&apos;dispatching&apos;</span>, action)\n  <span class="hljs-keyword">let</span> result = next(action)\n  <span class="hljs-built_in">console</span>.log(<span class="hljs-string">&apos;next state&apos;</span>, store.getState())\n  <span class="hljs-keyword">return</span> result\n}\n</code></pre>\n<pre><code class="language-js"><span class="hljs-comment">// &#x63D2;&#x4EF6;&#x4F7F;&#x7528;</span>\n<span class="hljs-keyword">import</span> { createStore, combineReducers, applyMiddleware } <span class="hljs-keyword">from</span> <span class="hljs-string">&apos;redux&apos;</span>\n\n<span class="hljs-keyword">const</span> todoApp = combineReducers(reducers)\n<span class="hljs-keyword">const</span> store = createStore(\n  todoApp,\n  <span class="hljs-comment">// applyMiddleware() tells createStore() how to handle middleware</span>\n  applyMiddleware(logger, crashReporter)\n)\n\n</code></pre>\n<p>// &#x590D;&#x6742;&#x6848;&#x4F8B;\n<a href="https://github.com/rt2zz/redux-persist#nested-persists">redux-persist</a></p>\n<h3 id="&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;"><a href="#&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;"></a>&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;&#x7684;&#x63D2;&#x4EF6;</h3>\n<ol>\n<li>redux-persist&#x7684;&#x63D2;&#x4EF6;&#xFF0C;&#x6216;&#x8005;&#x79F0;&#x4E3A; Transforms\n&#x4F8B;&#x5B50;</li>\n</ol>\n<pre><code class="language-js"><span class="hljs-keyword">import</span> createExpirationTransform <span class="hljs-keyword">from</span> <span class="hljs-string">&apos;redux-persist-transform-expire&apos;</span>;\n\n<span class="hljs-keyword">const</span> expireTransform = createExpirationTransform({\n  <span class="hljs-attr">expireKey</span>: <span class="hljs-string">&apos;customExpiresAt&apos;</span>,\n  <span class="hljs-attr">defaultState</span>: {\n    <span class="hljs-attr">custom</span>: <span class="hljs-string">&apos;values&apos;</span>\n  }\n});\n\npersistStore(store, {\n  <span class="hljs-attr">transforms</span>: [expireTransform]\n});\n</code></pre>\n<h2 id="&#x603B;&#x7ED3;"><a href="#&#x603B;&#x7ED3;"></a>&#x603B;&#x7ED3;</h2>\n<p>Vue&#x7684;mutable &#x6BD4; React&#x7684;immutable&#x5BF9;&#x6570;&#x636E;&#x7684;&#x72B6;&#x6001;&#x7684;&#x64CD;&#x4F5C;&#x6765;&#x7684;&#x76F4;&#x63A5;&#xFF0C;&#x5BFC;&#x81F4;&#x5728;&#x72B6;&#x6001;&#x5904;&#x7406;&#x63D2;&#x4EF6;&#x6A21;&#x5F0F;&#x4E5F;&#x4F1A;&#x4E0D;&#x540C;&#xFF1B;vuex&#xFF08;&#x76F4;&#x63A5;mutation&#x6539;&#x53D8;&#x6570;&#x636E;&#xFF09;&#x6574;&#x4F53;&#x4E0A;&#x6BD4;redux&#xFF08;&#x901A;&#x8FC7;dispatch action&#xFF0C;&#x8D70;&#x6574;&#x4E2A;reducer&#x6D41;&#x7A0B;&#x8FD4;&#x56DE;&#x65B0;&#x7684;state&#xFF09;&#x66F4;&#x52A0;&#x76F4;&#x63A5;&#xFF0C;&#x5BFC;&#x81F4;&#x63D2;&#x4EF6;&#x6A21;&#x5F0F;&#x4E0A;vuex&#x76F4;&#x63A5;&#x52AB;&#x6301;mutation&#x6BD4;redux&#x52AB;&#x6301;reducer&#x6765;&#x7684;&#x66F4;&#x52A0;&#x7B80;&#x5355;</p>\n<h2 id="Reference"><a href="#Reference"></a>Reference</h2>\n<ul>\n<li>https://vuex.vuejs.org/guide/plugins.html</li>\n<li>https://redux.js.org/understanding/history-and-design/middleware</li>\n<li>https://v2.vuejs.org/v2/guide/plugins.html?redirect=true</li>\n</ul>\n<h1 id="&#x6A21;&#x62DF;LRU&#x7684;&#x6570;&#x636E;&#x7ED3;&#x6784;&#xFF08;Set vs Array&#xFF09;"><a href="#&#x6A21;&#x62DF;LRU&#x7684;&#x6570;&#x636E;&#x7ED3;&#x6784;&#xFF08;Set vs Array&#xFF09;"></a>&#x6A21;&#x62DF;LRU&#x7684;&#x6570;&#x636E;&#x7ED3;&#x6784;&#xFF08;Set vs Array&#xFF09;</h1>\n<p>Set&#x4F1A;&#x81EA;&#x52A8;&#x8FFD;&#x8E2A;&#x63D2;&#x5165;&#x7684;&#x5148;&#x540E;&#x987A;&#x5E8F;</p>\n<ol>\n<li>Set&#x7ED3;&#x6784;</li>\n</ol>\n<pre><code class="language-js"><span class="hljs-keyword">let</span> s = <span class="hljs-keyword">new</span> <span class="hljs-built_in">Set</span>()\n\ns.add(<span class="hljs-number">3</span>)\ns.add(<span class="hljs-number">2</span>)\n\n<span class="hljs-comment">// make this key the freshest</span>\ns.delete(<span class="hljs-number">3</span>)\ns.add(<span class="hljs-number">3</span>)\n\n<span class="hljs-comment">// get Oldest</span>\n<span class="hljs-built_in">console</span>.log(s.values().next().value); <span class="hljs-comment">//2</span>\n</code></pre>\n<ol start="2">\n<li>Array&#x7ED3;&#x6784;</li>\n</ol>\n<pre><code class="language-js"><span class="hljs-keyword">let</span> s = []\n\ns.push(<span class="hljs-number">2</span>)\ns.push(<span class="hljs-number">3</span>)\n\n<span class="hljs-comment">// make this key the freshest</span>\ns.splice(s.indexOf(<span class="hljs-number">3</span>))\ns.push(<span class="hljs-number">3</span>)\n\n<span class="hljs-comment">// get Oldest</span>\n<span class="hljs-built_in">console</span>.log(s[<span class="hljs-number">0</span>])\n</code></pre>\n<h1 id="ORM &#x6A21;&#x5757;&#x7EC4;&#x6210;"><a href="#ORM &#x6A21;&#x5757;&#x7EC4;&#x6210;"></a>ORM &#x6A21;&#x5757;&#x7EC4;&#x6210;</h1>\n<ul>\n<li>ORM\n<ul>\n<li>ORM\n<ul>\n<li>Engine (open db, connect dialect and db_path)</li>\n<li>Session(prepare for next operation,  open/close DB)</li>\n</ul>\n</li>\n<li>Dialect\n<ul>\n<li>dialect : db and dialect container</li>\n<li>sqlite3 : language type &lt;- map -&gt; db column type</li>\n<li>mysql ...</li>\n</ul>\n</li>\n<li>Schema (Parse a struct to a Schema instance)\n<ul>\n<li>&#x9759;&#x6001;&#x8BED;&#x8A00;&#xFF08;&#x4F8B;&#x5982; golang&#xFF09;&#xFF1A;type struct&#xFF08;Modal&#xFF09; &lt;- &#x53CD;&#x5C04; -&gt; Table Fields</li>\n<li>&#x52A8;&#x6001;&#x8BED;&#x8A00;&#xFF08;&#x4F8B;&#x5982; js&#xFF09;&#xFF1A;&#x624B;&#x52A8; Table Fields &#x521B;&#x5EFA; -&gt; Table Fields</li>\n</ul>\n</li>\n<li>Clause (SQL Builder)\n<ul>\n<li>generator: keyword sql string(vars) generation</li>\n<li>clause : depend on generator, set/build final sql string</li>\n</ul>\n</li>\n<li>Session ( SQL Execution )\n<ul>\n<li>raw: raw sql execution</li>\n<li>table: table operation</li>\n<li>record: ORM Open API (Find/Select/Update/Delete/Where/Limit ...) ,depend on Clause/clause &amp; table &amp; raw</li>\n<li>hooks: ORM Open API hook</li>\n<li>transaction: Atomicity/Consistency/Isolation/Durability</li>\n<li>migration</li>\n</ul>\n</li>\n</ul>\n</li>\n</ul>\n',e=[{level:1,title:"文章精读之设计原则/模式",children:[{level:2,title:"设计原则：SOLID原则",children:[]},{level:2,title:"设计模式",children:[{level:3,title:"Creational Patterns",children:[]},{level:3,title:"Behavioral Patterns",children:[]},{level:3,title:"Structural Patterns",children:[]}]},{level:2,title:"设计原则 vs 设计模式",children:[]},{level:2,title:"Reference",children:[]}]},{level:1,title:"关于继承",children:[{level:3,title:"Reference",children:[]}]},{level:1,title:"关于面向对象",children:[]},{level:1,title:"React状态管理",children:[]},{level:1,title:"文章精读之前端框架设计",children:[{level:2,title:"组件类型",children:[]},{level:2,title:"状态管理",children:[]},{level:2,title:"CSS方案",children:[]},{level:2,title:"构建工具",children:[]},{level:2,title:"Reference",children:[]}]},{level:1,title:"CSS Animation,Transition 原理",children:[{level:2,title:"总结",children:[]},{level:2,title:"Reference",children:[]}]},{level:1,title:"Vue运行时错误处理",children:[{level:2,title:"Reference",children:[]}]},{level:1,title:"插件对比（Vue vs React）",children:[{level:2,title:"插件",children:[{level:3,title:"插件的插件（Vuex vs Redux）",children:[]},{level:3,title:"插件的插件的插件",children:[]}]},{level:2,title:"总结",children:[]},{level:2,title:"Reference",children:[]}]},{level:1,title:"模拟LRU的数据结构（Set vs Array）",children:[]},{level:1,title:"ORM 模块组成",children:[]}];export{x as attributes,n as html,e as nestedHeaders};
